const e={name:"Fikon",icon:"fikon",category:"frukt",family:"Mullbärsväxter",familyLatin:"Moraceae",perennial:!0,lifespan:"50-100+ år",difficulty:"Medel",difficultyWhy:"Fikonet i sig är lättskött och förvånansvärt problemfritt. Utmaningen i Sverige är vinterskyddet - du måste ha en plan för hur din fikona ska klara vintern. Krukodling löser det elegant.",zones:{outdoor:[1],indoor:null,greenhouse:[1,2,3]},days:"Skörd år 2-3",spacing:"2-3 m",spacingNote:"Friland mot sydvägg. I kruka räcker 40-60 cm krukdiameter.",rowSpacing:"3-4 m",depth:"Rotklumpens djup",depthNote:"Plantera inte djupare än rotklumpen. I kruka: dräneringslager av lecakulor i botten.",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Fikon vill ha minst 8 timmars direkt sol - det är ett absolut krav. Halvskugga ger klena frukter och dålig skörd. Sydvägg eller soligt hörn är drömmen."},temperature:{min:-10,max:40,ideal:"20-35°C",detail:"Fikonet är en riktig solvärmare. Det tål kortvarigt ner mot -10°C (sortkänsligt), men rötterna klarar mer. I Sverige hinner vi normalt med en skörd per säsong - och den kräver minst 3 månader med 15°C+."},wind:{level:"Vindkänslig",detail:"Varm, vindskyddad plats - helst mot en sydvägg eller ett plank. Kall vind stressar växten och bromsar tillväxten rejält."}},watering:{need:"Medel-Hög",icon:"water",summary:"Riklig vattning under tillväxt och fruktbildning. Under mognad: minska vattningen - för mycket vatten ger smaklösa, vattniga frukter.",phases:[{phase:"Vår (uppstart)",need:"Medel",tip:"Börja vattna försiktigt när du ställer ut krukan eller ser nya blad. Öka gradvis."},{phase:"Sommar (tillväxt)",need:"Hög",tip:"Vattna rikligt - en krukodlad fikona kan behöva vatten varje dag i värmen. Torkar den ut kraftigt fäller den frukt."},{phase:"Mognad (aug-okt)",need:"Låg",tip:"Minska vattningen nu! Lite stress ger sötare, smakrikare fikon. För mycket vatten ger vattnig smak och risk för röta."},{phase:"Vinter",need:"Minimal",tip:"Under vintervila i kall källare: vattna bara en gång i månaden, eller inte alls om temperaturen är under 5°C."}],mistakes:["Vattnar för lite under sommaren - fikonet fäller frukt i protest","Vattnar för mycket under mognad - ger smaklösa frukter","Glömmer att kontrollera krukodlade fikon under vintervilan - jordklumpen får aldrig torka helt"],tip:"Fikonet talar om när det är törstigt - bladen hänger och ser slappa ut. Men vänta inte tills dess! Regelbunden vattning ger jämnare skörd."},soil:"Fikonet vill ha väldränerad jord - det HATAR stående vatten. En sandig-lerig blandning med lite grus fungerar utmärkt. I kruka: vanlig blomjord med inblandad perlit.",soilTips:["Dränering är A och O - lecakulor i botten av krukan","Blanda in perlit eller grus i planteringsjorden","Fikonet gillar lätt kalkrik jord - strö lite kalk om pH är lågt","I kruka: byt jord vart 3-4 år, eller rotbeskär och sätt tillbaka"],timeline:{1:[{phase:"Utställning",months:"Maj",icon:"seedling"},{phase:"Tillväxt",months:"Maj-juli",icon:"growth"},{phase:"Fruktmognad",months:"Aug-okt",icon:"harvest"},{phase:"Skörd",months:"Sept-okt",icon:"harvest"},{phase:"Intagning",months:"Nov",icon:"snowflake"},{phase:"Vintervila",months:"Nov-april",icon:"snowflake"}],4:[{phase:"Utställning",months:"Juni",icon:"seedling"},{phase:"Tillväxt",months:"Juni-aug",icon:"growth"},{phase:"Fruktmognad",months:"Aug-sept",icon:"harvest"},{phase:"Skörd",months:"Sept",icon:"harvest"},{phase:"Intagning",months:"Okt",icon:"snowflake"},{phase:"Vintervila",months:"Okt-maj",icon:"snowflake"}],6:[{phase:"Utställning",months:"Juni",icon:"seedling"},{phase:"Tillväxt",months:"Juni-aug",icon:"growth"},{phase:"Fruktmognad",months:"Aug-sept",icon:"harvest"},{phase:"Intagning",months:"Sept",icon:"snowflake"},{phase:"Vintervila",months:"Okt-maj",icon:"snowflake"}]},nutritionData:[{month:"Apr",N:1,P:1,K:1},{month:"Maj",N:4,P:3,K:2},{month:"Jun",N:7,P:5,K:3,label:"Full tillväxt"},{month:"Jul",N:6,P:5,K:5},{month:"Aug",N:3,P:3,K:7,label:"Mognad"},{month:"Sep",N:1,P:2,K:5}],nutritionTips:[{timing:"Vår (maj)",tip:"Ge kompost eller balkonggödsel när du ställer ut fikonet. Starta tillväxten rätt."},{timing:"Sommar (juni-juli)",tip:"Gödsla varannan vecka med flytande gödsel. Fikon är inte extremt näringskrävande - övergödsla inte."},{timing:"Slutet av augusti",tip:"SLUTA gödsla. Fikonet ska börja förbereda sig för vintervila. Sen gödsling ger mjuka skott som inte överlever vintern."},{timing:"Vinter",tip:"Ingen gödsling alls under vintervilan. Fikonet vilar."}],companions:{good:[{name:"Lavendel",icon:"herb",why:"Trivs i samma varma, torra miljö. Lockar pollinatörer och avskräcker bladlöss."},{name:"Rosmarin",icon:"herb",why:"Samma krav på sol och dränering. Vackert ihop i en medelhavsinspirerad plantering."},{name:"Ringblomma",icon:"flower",why:"Lockar nyttoinsekter och ger fin kontrast. Trivs i samma soliga läge."}],bad:[{name:"Skuggväxter",icon:"vegetable",why:"Fikonet kräver full sol - plantera inte skuggivande växter intill."}]},rotation:{avoid:[{name:"Fikon"}],avoidWhy:"Fikonet är inte lika känsligt för trötthetssjuka som stenfrukter, men en ny planta trivs bättre i färsk jord.",goodBefore:[{name:"Gröngödsling"}],goodBeforeWhy:"Näringsrik, väldränerad jord ger den bästa starten.",goodAfter:[{name:"Gröngödsling"}],goodAfterWhy:"Bygg upp jordstrukturen med gröngödsling."},varieties:[{name:"Bornholms Diamant",zones:[1,2,3],note:"Den vanligaste sorten i Sverige. Medelstor, gröngul frukt med underbar smak. Partenokarp (sätter frukt utan pollinering). Friland zon 1, växthus/kruka zon 2-3."},{name:"Brown Turkey",zones:[1,2,3],note:"Stor, brunröd frukt. Riklig bärare med mild, söt smak. Något tåligare köldmässigt. Nybörjarvänlig. Friland zon 1, växthus/kruka zon 2-3."},{name:"Hardy Chicago",zones:[1,2,3],note:"Känd för härdighet i USA - stammar tål -12°C, rötter ner till -29°C. Svårare att hitta i Sverige men värd att leta efter. Friland zon 1, växthus/kruka zon 2-3."},{name:"Negronne",zones:[1,2,3],note:"Liten, mörkviolett frukt med intensiv, rik smak. Kompakt träd - perfekt i kruka. Något känsligare för kyla."}],problems:[{name:"Spinnkvalster",symptom:"Bladen gulnar, fina spindelvävsliknande trådar. Värst i torr luft inomhus under vintern.",fix:"Duscha av hela plantan med ljummet vatten. Öka luftfuktigheten. Inspektera NOGA innan du tar in fikonet på hösten."},{name:"Fikonrost",symptom:"Bruna fläckar på bladens undersida. Vanligt vid hög luftfuktighet.",fix:"Plocka bort angripna blad. Se till att kronan har god luftcirkulation. Vattna aldrig på bladen."},{name:"Fruktfall",symptom:"Omogna frukter ramlar av utan uppenbar anledning.",fix:"Oftast stress: torka, temperatursvängningar eller att krukan flyttats. Håll en stabil miljö - fikonet gillar inte förändringar."},{name:"Inga frukter",symptom:"Frodig, fin planta som aldrig sätter frukt.",fix:"Tre vanliga orsaker: för lite sol (kräver 8+ timmar), för stor kruka (rötterna vill vara lite trängda) eller för mycket kväve (ger blad istället för frukt)."}],pollination:{selfFertile:!0,description:"Alla fikonsorter som säljs i Sverige är partenokarpa - de sätter frukt helt utan pollinering. Du behöver varken en andra planta eller insekter. Det är en av fikonets absoluta fördelar som balkong- och trädgårdsväxt.",groups:[{name:"Partenokarpa (alla säljs i Sverige)",varieties:["Bornholms Diamant","Brown Turkey","Hardy Chicago","Negronne"]}],tip:"Smyrnafikon (som kräver pollinering av fikonstekel) kan INTE odlas i Sverige. Alla sorter du hittar i handeln är partenokarpa och klarar sig helt på egen hand."},establishment:{description:"Fikonet är förvånansvärt snabbt att etablera. En köpt planta kan ge frukt redan andra året. Det viktigaste är att hitta rätt plats och ha en vinterskötselsplan.",years:[{year:"År 1",tasks:["Placera i full sol mot sydvägg eller soligt hörn","Vattna regelbundet - inte för mycket, inte för lite","Gödsla varannan vecka maj-augusti","Planera vinterskyddet redan nu - var ska fikonet stå?"]},{year:"År 2",tasks:["Förvänta dig de första frukterna!","Formklipp på våren: ta bort döda grenar och korsande skott","Pincera (knip av toppen på) långa skott för att stimulera förgrening","Ta bort alla frukter som inte hinner mogna på hösten"]},{year:"År 3+",tasks:["Full skörd: 20-60 frukter per säsong (krukodlad)","Rotbeskär vart 3-4 år om krukan inte kan bli större","Fikonet blir alltmer självgående - du känner rytmen nu"]}],protection:["Vinterskydd: frostfri källare, garage eller kallförråd (0-10°C) under vintervilan","Friland zon 1: linda in med jutesäck + 10-20 cm lövmulch runt rotzonen","Acklimera gradvis på våren - ställ inte direkt i full sol","Plocka bort alla omogna frukter på hösten - de hinner inte och stjäl energi"],tip:"Det bästa med fikon i kruka: rötterna vill faktiskt vara lite trängda! Det stimulerar fruktbildning. En 40-60 cm kruka räcker i decennier om du rotbeskär ibland."},ripeningGuide:{description:"Fikon mognar successivt från augusti till oktober i Sverige. Varje frukt mognar individuellt - du plockar inte alla på en gång utan besöker ditt fikonträd regelbundet under hösten.",entries:[{variety:"Bornholms Diamant",from:"aug",to:"okt",type:"Gröngult fikon"},{variety:"Brown Turkey",from:"aug",to:"okt",type:"Brunrött fikon"},{variety:"Hardy Chicago",from:"aug",to:"sep",type:"Mörkt fikon"},{variety:"Negronne",from:"sep",to:"okt",type:"Violett fikon"}],tip:"Ett moget fikon hänger nedåt, är mjukt vid tryck, har skrynklig yta och en liten droppe vid öppningen. Det lossnar nästan av sig självt. Ät det direkt - hemodlade, solmogna fikon är en helt annan dimension än importerade."},goodToKnow:[{icon:"warning",title:"Vinterskydd - den enda riktiga utmaningen",text:"Allt annat med fikon är enkelt. MEN: du måste ha en plan för vintern. Krukodlat fikon ställs in i frostfri, mörk källare (0-10°C) i november. Vänta tills bladen fallit av sig själva innan du tar in. På friland (zon 1): linda in hela busken med jutesäck och mulcha rotzonen rejält.",severity:"warning"},{icon:"tip",title:"Trängda rötter = mer frukt",text:"Fikonet sätter mer frukt när rötterna är begränsade. Välj INTE en för stor kruka! 40-60 cm diameter räcker utmärkt. På friland kan du gräva ner en gammal kruka eller betongring runt rotzonen för att begränsa tillväxten.",severity:"tip"},{icon:"tip",title:"Sticklingar - löjligt enkelt",text:"Fikon är ett av de enklaste fruktträden att föröka med sticklingar. Ta 15-20 cm långa kvistar på våren, stick ner i fuktig jord, och vänta. De rotar sig nästan alltid. Perfekt present till odlarvänner!",severity:"tip"},{icon:"warning",title:"Plocka bort omogna frukter på hösten",text:"De ärtsorstora frukterna som sitter kvar i september-oktober hinner ALDRIG mogna. Ta bort dem - de stjäl energi som fikonet behöver för vintervilan. Nästa års frukter bildas på nya skott.",severity:"warning"}],sowing:{method:"direct",label:"Plantering",description:"Fikon planteras som färdiga plantor. I Sverige är krukodling den normala formen - ställ ut på sommaren och ta in för vintervila.",steps:["Välj en kruka på 40-60 cm med dräneringshål","Lägg ett lager lecakulor i botten (3-5 cm)","Fyll med blomjord blandat med perlit (20%)","Plantera i krukans mitt, inte djupare än rotklumpen","Vattna rikligt efter plantering","Ställ i fullsol mot sydvägg"],tips:["Krukodling är standard i Sverige - det ger dig full kontroll över vinterskyddet","Välj Bornholms Diamant eller Brown Turkey som första sort - säkrast resultat","Frilandsplantering bara i zon 1 (södra Skåne, Gotland, Öland) i extremt skyddat sydläge"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Sticklingar",biennial:!1,description:"Fikon förökas enklast med sticklingar - det är nästan omöjligt att misslyckas. Att odla från frön ger inte samma sort och tar mycket längre tid.",steps:["Ta 15-20 cm långa kvistar i tidig vår (innan bladen slår ut)","Välj blyertstjocka eller kraftigare grenar","Stick ner i fuktig planteringsjord med perlit","Täck med perforerad plastpåse för att hålla fukten","Håll svalt (15-20°C) och skuggigt","Rötter bildas på 3-6 veckor"],isolation:"Sticklingar ger exakta kloner av moderplantan.",storageYears:"Kvistar kan förvaras i fuktig tidning i kylskåp 2-3 månader",tip:"Ta gärna 3-5 sticklingar åt gången - de rotar sig nästan alla. Perfekt present till odlarvänner som drömmer om egna fikon!"},storage:{shelfLife:"1-3 dagar (färska), 6+ månader (torkade)",methods:[{method:"Färska (direkt)",icon:"cellar",duration:"1-3 dagar",description:"Hemodlade fikon ska ätas direkt! Det är hela poängen. De håller sig max 1-2 veckor i kylskåp men tappar smak för varje dag.",best:!0},{method:"Torkning",icon:"sun",duration:"6+ månader",description:"Halvera och torka i ugn vid 50-60°C i 6-8 timmar. Torkade fikon är fantastiskt goda och håller sig länge i lufttät burk.",best:!1},{method:"Frysning",icon:"snowflake",duration:"10-12 månader",description:"Frysa hela eller halverade fikon. Funkar för sylt, smoothies och bakning - men inte för färskätning.",best:!1},{method:"Sylt",icon:"storage",duration:"1+ år",description:"Fikonsylt med vanilj och citron - en klassiker. Fikonen behöver knappt socker, de är naturligt söta.",best:!1}],tips:["Mogna fikon ska ätas samma dag eller dagen efter - de är extremt färskvaror","Butiksfikonens smaklöshet beror på att de skördas omogna för transport - dina egna är en annan dimension","Torkade fikon i lufttät burk på sval plats håller i månader"]},harvestCalc:{minPerSqm:1,maxPerSqm:4,unit:"kg per planta (år 3+)"},pruning:{label:"Beskärning",types:{spring:{name:"Vårbeskärning (formklipp)",when:"Mars-april (innan knoppsprickning)",description:"Fikonet beskärs på våren för att forma kronan och ta bort vinterskadade grenar. Det tål kraftig beskärning väl - var inte rädd!",steps:["Ta bort döda, skadade och korsande grenar","Skär tillbaka till 3-5 starka huvudgrenar","Pincera (knip av toppen på) långa skott för att stimulera förgrening","Ta bort alla rotskott som växer runt basen"]}}},propagation:{difficulty:"Enkel",methods:[{method:"Sticklingar",description:"Det enklaste sättet. Ta 15-20 cm kvistar i tidig vår, stick ner i fuktig jord. Rotar sig på 3-6 veckor. Nästan omöjligt att misslyckas.",icon:"seedling"},{method:"Luftavläggare",description:"Möjligt men onödigt komplicerat när sticklingar fungerar så bra. Används när man vill ha en stor planta snabbt.",icon:"seed"}],tip:"Fikon är löjligt enkelt att föröka. En enda gren kan ge dig 3-5 nya plantor. Börja med sticklingar - du kommer bli förvånad hur bra det går."}};export{e as fikon};
